selector_to_html = {"a[href=\"#rust\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Rust<a class=\"headerlink\" href=\"#rust\" title=\"Link to this heading\">\uf0c1</a></h3>", "a[href=\"cpp_testing.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">C++ Testing<a class=\"headerlink\" href=\"#c-testing\" title=\"Link to this heading\">\uf0c1</a></h1><p><code class=\"docutils literal notranslate\"><span class=\"pre\">cc_test</span></code> (from <code class=\"docutils literal notranslate\"><span class=\"pre\">//bzl:cc.bzl</span></code>) is the single rule for all C++ tests. It\nauto-selects the right underlying framework based on your includes:</p>", "a[href=\"#javascript-node\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">JavaScript / Node<a class=\"headerlink\" href=\"#javascript-node\" title=\"Link to this heading\">\uf0c1</a></h3>", "a[href=\"#language-faqs\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Language FAQs<a class=\"headerlink\" href=\"#language-faqs\" title=\"Link to this heading\">\uf0c1</a></h2><p>Each language answers: how to lint/format, build, test, run, add dependencies,\npackage, and release.</p>", "a[href=\"#development-guide\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Development Guide<a class=\"headerlink\" href=\"#development-guide\" title=\"Link to this heading\">\uf0c1</a></h1><p>See <a class=\"reference internal\" href=\"structure.html\"><span class=\"std std-doc\">structure</span></a> for the full directory map.</p>", "a[href=\"#adding-a-new-file-type\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Adding a new file type<a class=\"headerlink\" href=\"#adding-a-new-file-type\" title=\"Link to this heading\">\uf0c1</a></h3>", "a[href=\"#build-and-test\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Build and Test<a class=\"headerlink\" href=\"#build-and-test\" title=\"Link to this heading\">\uf0c1</a></h2>", "a[href=\"#git-lfs\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Git LFS<a class=\"headerlink\" href=\"#git-lfs\" title=\"Link to this heading\">\uf0c1</a></h2><p>Large binary files (firmware images, photos, archives) are tracked via\n<a class=\"reference external\" href=\"https://git-lfs.com/\">Git LFS</a>. The patterns are configured in\n<a class=\"reference internal\" href=\"#../.gitattributes\"><span class=\"xref myst\"><code class=\"docutils literal notranslate\"><span class=\"pre\">.gitattributes</span></code></span></a>.</p><p>The <code class=\"docutils literal notranslate\"><span class=\"pre\">git-lfs</span></code> binary is managed via\n<a class=\"reference external\" href=\"https://github.com/theoremlp/rules_multitool\">rules_multitool</a> and can be run\ndirectly from the repo root:</p>", "a[href=\"#installation\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Installation<a class=\"headerlink\" href=\"#installation\" title=\"Link to this heading\">\uf0c1</a></h2><p>Install <a class=\"reference external\" href=\"https://github.com/bazelbuild/bazelisk\">bazelisk</a> as your <code class=\"docutils literal notranslate\"><span class=\"pre\">bazel</span></code>\nbinary:</p>", "a[href=\"#c\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">C++<a class=\"headerlink\" href=\"#c\" title=\"Link to this heading\">\uf0c1</a></h3><p><strong>Style:</strong> C++23, clang-format (<code class=\"docutils literal notranslate\"><span class=\"pre\">.clang-format</span></code>)</p><p>Use <code class=\"docutils literal notranslate\"><span class=\"pre\">cc_test</span></code> (from <code class=\"docutils literal notranslate\"><span class=\"pre\">//bzl:cc.bzl</span></code>) for all tests \u2014 see\n<a class=\"reference internal\" href=\"cpp_testing.html\"><span class=\"std std-doc\">cpp_testing</span></a> for details.</p>", "a[href=\"#linting-and-formatting\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Linting and Formatting<a class=\"headerlink\" href=\"#linting-and-formatting\" title=\"Link to this heading\">\uf0c1</a></h2>", "a[href=\"#ci\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">CI<a class=\"headerlink\" href=\"#ci\" title=\"Link to this heading\">\uf0c1</a></h2>", "a[href=\"structure.html\"]": "<h1 class=\"tippy-header\" style=\"margin-top: 0;\">Repository Structure<a class=\"headerlink\" href=\"#repository-structure\" title=\"Link to this heading\">\uf0c1</a></h1><h2>Overview<a class=\"headerlink\" href=\"#overview\" title=\"Link to this heading\">\uf0c1</a></h2><p>All project code lives under the <code class=\"docutils literal notranslate\"><span class=\"pre\">tlbox/</span></code> top-level directory. This is a\nlanguage-agnostic namespace \u2014 Python, C++, Rust, hardware, and documentation all\ncoexist under it. The namespace doubles as the Python package name and is\nreserved on PyPI, BCR, and npm for future publishing.</p><p>Build infrastructure, platform definitions, and vendored dependencies live\noutside <code class=\"docutils literal notranslate\"><span class=\"pre\">tlbox/</span></code> at the repo root.</p>", "a[href=\"#common-operations\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Common operations<a class=\"headerlink\" href=\"#common-operations\" title=\"Link to this heading\">\uf0c1</a></h3>", "a[href=\"#first-time-setup\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">First-time setup<a class=\"headerlink\" href=\"#first-time-setup\" title=\"Link to this heading\">\uf0c1</a></h3>", "a[href=\"#bazel\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Bazel<a class=\"headerlink\" href=\"#bazel\" title=\"Link to this heading\">\uf0c1</a></h3><p><strong>References:</strong> <a class=\"reference external\" href=\"https://bazel.build/query/language\">Bazel query language</a>,\n<a class=\"reference external\" href=\"https://bazel.build/external/migration\">bzlmod migration</a></p>", "a[href=\"#python\"]": "<h3 class=\"tippy-header\" style=\"margin-top: 0;\">Python<a class=\"headerlink\" href=\"#python\" title=\"Link to this heading\">\uf0c1</a></h3><p><strong>Style:</strong> 79-char line length (black + isort via <code class=\"docutils literal notranslate\"><span class=\"pre\">pyproject.toml</span></code>)</p>", "a[href=\"#inspiration\"]": "<h2 class=\"tippy-header\" style=\"margin-top: 0;\">Inspiration<a class=\"headerlink\" href=\"#inspiration\" title=\"Link to this heading\">\uf0c1</a></h2>"}
skip_classes = ["headerlink", "sd-stretched-link"]

window.onload = function () {
    for (const [select, tip_html] of Object.entries(selector_to_html)) {
        const links = document.querySelectorAll(` ${select}`);
        for (const link of links) {
            if (skip_classes.some(c => link.classList.contains(c))) {
                continue;
            }

            tippy(link, {
                content: tip_html,
                allowHTML: true,
                arrow: true,
                placement: 'auto-start', maxWidth: 500, interactive: false,

            });
        };
    };
    console.log("tippy tips loaded!");
};
